import React from 'react';
import { FileText, BarChart3, Clock, Image as ImageIcon } from 'lucide-react';
import { QueryResponse } from '../types';

interface SourceDocument {
  doc_id: string;
  chunk_id: string;
  text: string;
  score: number;
  images?: Array<{
    image_id: string;
    ocr_text?: string;
  }>;
}

interface QueryResponseProps {
  response: QueryResponse | null;
}

export const QueryResponseDisplay: React.FC<QueryResponseProps> = ({ response }) => {
  if (!response) return null;

  return (
    <div className="futuristic-card p-8 mt-6">
      <div className="flex items-center mb-6">
        <FileText className="w-8 h-8 text-green-400 mr-3" />
        <h2 className="text-2xl font-bold text-futuristic">Neural Response</h2>
      </div>

      <div className="space-y-6">
        <div>
          <h3 className="text-xl font-semibold text-cyan-400 mb-4">Generated Answer</h3>
          <div className="p-6 bg-gray-800/50 rounded-lg border border-cyan-500/20">
            <p className="text-gray-100 whitespace-pre-wrap leading-relaxed">{response.answer}</p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <div>
            <h3 className="text-xl font-semibold text-cyan-400 mb-4 flex items-center">
              <BarChart3 className="w-6 h-6 mr-2" />
              Confidence Matrix
            </h3>
            <div className="p-6 bg-gray-800/50 rounded-lg border border-cyan-500/20">
              <div className="flex items-center">
                <div className="flex-1 bg-gray-700 rounded-full h-3 mr-4">
                  <div
                    className="bg-gradient-to-r from-cyan-400 to-blue-500 h-3 rounded-full transition-all duration-500 shadow-lg shadow-cyan-500/50"
                    style={{ width: `${(response.confidence || 0) * 100}%` }}
                  />
                </div>
                <span className="text-lg font-semibold text-cyan-300">
                  {Math.round((response.confidence || 0) * 100)}%
                </span>
              </div>
            </div>
          </div>

          <div>
            <h3 className="text-xl font-semibold text-cyan-400 mb-4">Retrieval Sources</h3>
            <div className="p-6 bg-gray-800/50 rounded-lg border border-cyan-500/20 max-h-96 overflow-y-auto">
              {response.sources && response.sources.length > 0 ? (
                <ul className="space-y-4">
                  {(response.sources as unknown[]).map((source, index) => {
                    const sourceDoc = source as SourceDocument;
                    return (
                      <li key={index} className="text-sm text-gray-300">
                        <div className="mb-2">
                          <span className="font-mono text-cyan-400">Source {index + 1}:</span>
                          <span className="ml-2 text-gray-400">(Score: {sourceDoc.score?.toFixed(3)})</span>
                        </div>
                        <div className="p-3 bg-gray-900/50 rounded border border-cyan-500/10">
                          <p className="text-gray-200 text-sm leading-relaxed">{sourceDoc.text}</p>
                          {sourceDoc.images && sourceDoc.images.length > 0 && (
                            <div className="mt-3 pt-3 border-t border-cyan-500/20">
                              <div className="flex items-center mb-2">
                                <ImageIcon className="w-4 h-4 text-cyan-400 mr-2" />
                                <span className="text-xs font-semibold text-cyan-300">
                                  {sourceDoc.images.length} Image(s) Found
                                </span>
                              </div>
                              {sourceDoc.images.map((img, imgIndex) => (
                                <div key={imgIndex} className="ml-6 mb-2 p-2 bg-gray-800/50 rounded border border-cyan-500/10">
                                  <div className="text-xs text-gray-400 font-mono">
                                    Image ID: {img.image_id}
                                  </div>
                                  {img.ocr_text && (
                                    <div className="text-xs text-gray-300 mt-1 italic">
                                      OCR: "{img.ocr_text}"
                                    </div>
                                  )}
                                </div>
                              ))}
                            </div>
                          )}
                        </div>
                      </li>
                    );
                  })}
                </ul>
              ) : (
                <p className="text-sm text-gray-400">No sources retrieved</p>
              )}
            </div>
          </div>
        </div>

        {response.meta && (
          <div>
            <h3 className="text-xl font-semibold text-cyan-400 mb-4 flex items-center">
              <Clock className="w-6 h-6 mr-2" />
              Neural Analysis Metadata
            </h3>
            <div className="p-6 bg-gray-800/50 rounded-lg border border-cyan-500/20">
              <pre className="text-xs text-gray-300 overflow-x-auto font-mono">
                {JSON.stringify(response.meta, null, 2)}
              </pre>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};
